// Calculate the optimal posting time in IST
const postData = $input.first().json;
const webhookData = $('Webhook: Receive Approval').first().json.body;

// If the dashboard sent a specific scheduled_at, use it
if (webhookData.scheduled_at) {
  return [{ json: { ...postData, scheduled_at: webhookData.scheduled_at } }];
}

// Otherwise calculate the next optimal slot
// IST = UTC + 5:30
const istOffset = 5.5 * 60 * 60 * 1000;
const nowUTC = new Date();
const nowIST = new Date(nowUTC.getTime() + istOffset);

const hourIST = nowIST.getUTCHours();
const minIST = nowIST.getUTCMinutes();
const dayIST = nowIST.getUTCDay(); // 0=Sun, 6=Sat

const isWeekday = dayIST >= 1 && dayIST <= 5;
let targetIST = new Date(nowIST);

if (isWeekday && (hourIST < 8 || (hourIST === 7 && minIST < 55))) {
  // Morning slot: today 8:00 AM IST
  targetIST.setUTCHours(8, 0, 0, 0);
} else if (isWeekday && hourIST < 18) {
  // Evening slot: today 6:00 PM IST  
  targetIST.setUTCHours(18, 0, 0, 0);
} else {
  // Next weekday morning
  targetIST.setUTCDate(targetIST.getUTCDate() + 1);
  while (targetIST.getUTCDay() === 0 || targetIST.getUTCDay() === 6) {
    targetIST.setUTCDate(targetIST.getUTCDate() + 1);
  }
  targetIST.setUTCHours(8, 0, 0, 0);
}

// Convert back to UTC for n8n Wait node
const scheduledUTC = new Date(targetIST.getTime() - istOffset);

console.log(`Post scheduled for: ${targetIST.toISOString()} IST (${scheduledUTC.toISOString()} UTC)`);

return [{
  json: {
    post_id: postData[0]?.id || webhookData.post_id,
    idea_title: postData[0]?.idea_title || 'AI Post',
    linkedin_draft: postData[0]?.linkedin_draft || '',
    instagram_draft: postData[0]?.instagram_draft || '',
    whatsapp_draft: postData[0]?.whatsapp_draft || '',
    image_url: postData[0]?.image_url || '',
    scheduled_at: scheduledUTC.toISOString(),
    scheduled_at_ist: `${targetIST.toISOString().substring(0,16).replace('T',' ')} IST`
  }
}];

