// Collect platform post IDs from all publishing steps
const items = $input.all();
const scheduled = $('Code: Calculate Optimal Schedule Time').first().json;

// LinkedIn response has id field
const liResponse = items.find(i => i.json.id && typeof i.json.id === 'string' && i.json.id.startsWith('urn:li:'));
const liPostId = liResponse?.json?.id || '';

// Instagram publish response has id field (numeric string)
const igResponse = items.find(i => i.json.id && !String(i.json.id).startsWith('urn:'));
const igPostId = igResponse?.json?.id || '';

// WhatsApp response
const waResponse = items.find(i => i.json.messages);
const waMessageId = waResponse?.json?.messages?.[0]?.id || '';

console.log(`Published - LinkedIn: ${liPostId}, Instagram: ${igPostId}, WhatsApp: ${waMessageId}`);

return [{
  json: {
    post_id: scheduled.post_id,
    linkedin_post_id: liPostId,
    instagram_post_id: igPostId,
    whatsapp_message_id: waMessageId,
    published_at: new Date().toISOString(),
    idea_title: scheduled.idea_title
  }
}];

// Calculate performance score from LinkedIn + Instagram analytics
const items = $input.all();
const publishedData = $('Supabase: Mark as Published').first().json;
const originalPost = $('Code: Calculate Optimal Schedule Time').first().json;

// Parse LinkedIn metrics
const liData = items.find(i => i.json.likesSummary || i.json.totalSocialActivityCounts) || {};
const liLikes = liData.json?.likesSummary?.totalLikes || liData.json?.totalSocialActivityCounts?.numLikes || 0;
const liComments = liData.json?.commentsSummary?.totalFirstLevelComments || liData.json?.totalSocialActivityCounts?.numComments || 0;
const liShares = liData.json?.totalSocialActivityCounts?.numShares || 0;
const liImpressions = liData.json?.totalShareStatistics?.impressionCount || liLikes * 50; // estimate if not available

// Parse Instagram metrics
const igRawData = items.find(i => i.json.data && Array.isArray(i.json.data));
const igMetrics = {};
(igRawData?.json?.data || []).forEach(m => { igMetrics[m.name] = m.values?.[0]?.value || 0; });
const igLikes = igMetrics.likes || 0;
const igComments = igMetrics.comments || 0;
const igReach = igMetrics.reach || 0;
const igSaves = igMetrics.saved || 0;

// Weighted score (0–100)
// LinkedIn weight: 60%, Instagram weight: 40%
const liEngRate = liImpressions > 0 ? (liLikes + liComments * 3 + liShares * 5) / liImpressions * 100 : 0;
const igEngRate = igReach > 0 ? (igLikes + igComments * 3 + igSaves * 4) / igReach * 100 : 0;
const score = Math.min(100, Math.round((liEngRate * 60 + igEngRate * 40) * 10) / 10);

// Label performance
const label = score >= 7 ? 'HIGH' : score >= 3 ? 'MEDIUM' : 'LOW';

console.log(`Performance score: ${score}/100 (${label}) | LI: ${liLikes}👍 ${liComments}💬 | IG: ${igLikes}❤️ ${igReach} reach`);

return [{
  json: {
    post_id: originalPost.post_id,
    li_likes: liLikes,
    li_comments: liComments,
    li_shares: liShares,
    li_impressions: liImpressions,
    ig_likes: igLikes,
    ig_comments: igComments,
    ig_reach: igReach,
    ig_saves: igSaves,
    performance_score: score,
    performance_label: label,
    score_notes: `LI eng: ${liEngRate.toFixed(2)}% | IG eng: ${igEngRate.toFixed(2)}% | Combined: ${score}/100`,
    analyzed_at: new Date().toISOString()
  }
}];

